// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{})
}

type ChiServerOptions struct {
	BaseURL          string
	BaseRouter       chi.Router
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, r chi.Router) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseRouter: r,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, r chi.Router, baseURL string) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseURL:    baseURL,
		BaseRouter: r,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options ChiServerOptions) http.Handler {
	r := options.BaseRouter

	if r == nil {
		r = chi.NewRouter()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}
	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/companies", wrapper.ListCompanies)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/v1/companies", wrapper.CreateCompany)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/api/v1/companies/{companyId}", wrapper.DeleteCompany)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/companies/{companyId}", wrapper.GetCompany)
	})
	r.Group(func(r chi.Router) {
		r.Patch(options.BaseURL+"/api/v1/companies/{companyId}", wrapper.UpdateCompany)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/entries", wrapper.ListEntries)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/v1/entries", wrapper.CreateEntry)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/api/v1/entries/{entryId}", wrapper.DeleteEntry)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/entries/{entryId}", wrapper.GetEntry)
	})
	r.Group(func(r chi.Router) {
		r.Patch(options.BaseURL+"/api/v1/entries/{entryId}", wrapper.UpdateEntry)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/entries/{entryId}/tasks", wrapper.ListTasks)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/v1/entries/{entryId}/tasks", wrapper.CreateTask)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/api/v1/tasks/{taskId}", wrapper.DeleteTask)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/tasks/{taskId}", wrapper.GetTask)
	})
	r.Group(func(r chi.Router) {
		r.Patch(options.BaseURL+"/api/v1/tasks/{taskId}", wrapper.UpdateTask)
	})

	return r
}
